SELECT U.USER_NO AS userNo, U.USER_NAME AS userName, U.EMAIL AS email, U.PHONE AS phone, U.PROVIDER AS provider, U.CREATED_AT AS createdAt, U.STATUS AS status, U.DELETE_AT AS deleteAt, U.AUTH AS auth, A.ACCOUNT_NO AS accountNo, A.STATUS AS accountStatus, A.STOP_END_AT AS stopEndAt FROM USERS U LEFT JOIN ACCOUNTS A ON U.USER_NO = A.USER_NO WHERE 1 = 1
AND ( U.USER_NAME LIKE '%' || #{keyword} || '%' OR NVL(U.EMAIL, '') LIKE '%' || #{keyword} || '%' OR NVL(U.PHONE, '') LIKE '%' || #{keyword} || '%' )
AND U.STATUS = #{status}
AND U.AUTH = #{auth}
ORDER BY U.USER_NO DESC

